CREATE OR REPLACE VIEW vr_wef_ext_by_day (membership_no, requestment_no, age_meme, paid_date, total_receive, remark, operate_date, approve_date, wef_type, bank_acc_no, money_type_id, return_status) AS select sc_wef_req.membership_no,
       sc_wef_req.requestment_no,
       pka_lon_reqsrv.fp_calc_agetext(pka_srv_datetime.fp_monthsafter(sc_mem_m_membership_registered.approve_date,sc_wef_req.operate_date)) as age_meme,
       (select max(paid_date) FROM sc_fin_money_return where sc_wef_req.requestment_no = sc_fin_money_return.refno1) as paid_date,
       sc_wef_req.total_receive,
       sc_wef_req_ext.remark,
       sc_wef_req.operate_date,
       sc_wef_req.approve_date,
       sc_wef_req.wef_type,
       sc_wef_req.bank_acc_no,
       sc_wef_req.money_type_id,
       (select max(sc_fin_money_return.return_status) from sc_fin_money_return where sc_fin_money_return.refno1 = sc_wef_req.requestment_no
                                                                            and sc_fin_money_return.cancel_status = '0') as return_status
from sc_wef_req,sc_wef_req_ext,sc_mem_m_membership_registered
where sc_wef_req.requestment_no = sc_wef_req_ext.requestment_no
and sc_mem_m_membership_registered.membership_no = sc_wef_req.membership_no
and sc_wef_req.cancel_status = '0'
and sc_wef_req.approve_status = '1'
and sc_wef_req.wef_type = 'EXT';

